import{_ as e,o as a,c as o,a3 as r}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"Technical Specifications","description":"","frontmatter":{"title":"Technical Specifications"},"headers":[],"relativePath":"en/advertisers/sponsored-mail/design-guide/print-specs.md","filePath":"en/advertisers/sponsored-mail/design-guide/print-specs.md"}'),s={name:"en/advertisers/sponsored-mail/design-guide/print-specs.md"};function i(l,t,n,d,g,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="technical-specifications" tabindex="-1">Technical Specifications <a class="header-anchor" href="#technical-specifications" aria-label="Permalink to &quot;Technical Specifications&quot;">​</a></h1><p>The constraints to respect to guarantee optimal print quality and high-performance tracking.</p><hr><h2 id="paper-formats" tabindex="-1">Paper Formats <a class="header-anchor" href="#paper-formats" aria-label="Permalink to &quot;Paper Formats&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Finished (cut)</th><th style="text-align:left;">File (with bleed)</th><th style="text-align:left;">Safe zone</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A5</strong></td><td style="text-align:left;">148 × 210 mm</td><td style="text-align:left;"><strong>152 × 214 mm</strong></td><td style="text-align:left;">3 mm internal</td></tr><tr><td style="text-align:left;"><strong>A6</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;"><strong>109 × 152 mm</strong></td><td style="text-align:left;">3 mm internal</td></tr><tr><td style="text-align:left;"><strong>Card</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;"><strong>109 × 152 mm</strong></td><td style="text-align:left;">See template</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Bleed: 2 mm mandatory</p><p>The material (image or colored background) must extend <strong>2 mm outside</strong> the finished format. Without bleed, a white border appears after cutting.</p></div><div class="tip custom-block"><p class="custom-block-title">Safe zone: 3 mm</p><p>No text, logo, or important element should be less than <strong>3 mm from the inner edge</strong>. Anything too close to the edge risks being cropped.</p></div><hr><h2 id="files-colorimetry" tabindex="-1">Files &amp; Colorimetry <a class="header-anchor" href="#files-colorimetry" aria-label="Permalink to &quot;Files &amp; Colorimetry&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Criterion</th><th style="text-align:left;">Specification</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>File format</strong></td><td style="text-align:left;">PDF/X (vector) — preferred. JPG or PNG accepted.</td></tr><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><strong>300 DPI minimum</strong></td></tr><tr><td style="text-align:left;"><strong>Color mode</strong></td><td style="text-align:left;"><strong>CMYK mandatory</strong> (no RGB)</td></tr><tr><td style="text-align:left;"><strong>ICC Profile</strong></td><td style="text-align:left;">Coated FOGRA39</td></tr><tr><td style="text-align:left;"><strong>Ink coverage</strong></td><td style="text-align:left;"><strong>Maximum 300%</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Tip — Deep Black</p><p>For a rich black on solid areas (large black backgrounds): use <strong>C30% M30% Y30% K100%</strong>. For fine texts and small characters: use <strong>K100% only</strong> to avoid shifting during printing.</p></div><hr><h2 id="paper" tabindex="-1">Paper <a class="header-anchor" href="#paper" aria-label="Permalink to &quot;Paper&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Recommended paper specifications</p><ul><li><strong>Weight:</strong> 250 to 300 g/m²</li><li><strong>Type:</strong> Matte coated or semi-matte coated</li><li><strong>Certification:</strong> FSC or PEFC</li><li><strong>Lamination:</strong> No — lamination makes QR codes less readable</li></ul></div><hr><h2 id="getinside-qr-code" tabindex="-1">getinside QR Code <a class="header-anchor" href="#getinside-qr-code" aria-label="Permalink to &quot;getinside QR Code&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Proprietary QR code mandatory</p><p>You <strong>cannot</strong> use a QR code generated by yourself. You must imperatively integrate the <strong><code>.svg</code></strong> file provided by the getinside platform.</p><p><strong>Why?</strong> This unique QR code certifies distribution, enables real-time monitoring, and activates your performance dashboard.</p></div><p><strong>Minimum size: 25 × 25 mm</strong> (below this, the QR code is not readable by all smartphones).</p><div class="gi-value-grid"><div class="gi-value-card"><strong>✨ Dynamic QR Code</strong><p>The destination URL is not engraved in the code&#39;s pattern.</p><p>You can change the landing page at any time from the platform — <strong>even after the flyers are printed</strong>. Ideal for correcting a URL error or extending an offer.</p></div><div class="gi-value-card"><strong>🎯 Tracking &amp; UTM</strong><p>getinside measures scans. To track <strong>sales</strong> in Google Analytics, configure the URL with UTM parameters:</p><p><code>mysite.com?utm_source=getinside&amp;utm_medium=parcel-insert&amp;utm_campaign=spring</code></p><p>Also add a <strong>unique promo code</strong> per distributor for offline attribution.</p></div></div><hr><h2 id="sample-formats-sampling" tabindex="-1">Sample Formats (Sampling) <a class="header-anchor" href="#sample-formats-sampling" aria-label="Permalink to &quot;Sample Formats (Sampling)&quot;">​</a></h2><p>getinside allows the distribution of samples alone or assembled with a flyer.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Max weight</th><th style="text-align:left;">Max developed (H + W + L)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Format S</strong></td><td style="text-align:left;">15 g</td><td style="text-align:left;">15 cm</td></tr><tr><td style="text-align:left;"><strong>Format M</strong></td><td style="text-align:left;">100 g</td><td style="text-align:left;">30 cm</td></tr><tr><td style="text-align:left;"><strong>Format L</strong></td><td style="text-align:left;">450 g</td><td style="text-align:left;">40 cm</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">&quot;Duo&quot; Option — Flyer + Sample Assembly (Format S)</p><p>The sample is glued to an A5 or A6 flyer via a dot of <strong>fugitive glue</strong> (repositionable), allowing it to be detached without damaging the flyer.</p><p>This service is performed by <strong>Adapted Enterprises (EA)</strong>, promoting the employment of disabled workers.</p></div><hr><h2 id="proof-bat-checklist" tabindex="-1">Proof (BAT) Checklist <a class="header-anchor" href="#proof-bat-checklist" aria-label="Permalink to &quot;Proof (BAT) Checklist&quot;">​</a></h2><p>To check before each submission:</p><ol><li>Dimensions include <strong>+2 mm bleed</strong> and respect <strong>-3 mm safe zone</strong>.</li><li>File is in <strong>CMYK (FOGRA39)</strong>, resolution ≥ <strong>300 DPI</strong>, ink coverage ≤ <strong>300%</strong>.</li><li>getinside QR code (<code>.svg</code>) is present and measures at least <strong>25 × 25 mm</strong>.</li><li>Universal legal notices are included: advertiser ID, Triman, getinside logo, T&amp;Cs.</li><li>Mandatory sectorial notices (if applicable) are legible.</li></ol><p>→ <a href="https://docs.google.com/document/d/17oybJkf4iOX0XrC4LOJSI0zp2y0w_Wn7F4GW_oBAZcM/edit" target="_blank">Download the complete Checklist</a></p>',29)])])}const h=e(s,[["render",i]]);export{p as __pageData,h as default};
